import { format, parse } from 'date-fns'

export function parseDateString(date: string, fallback?: string) {
  try {
    let val = date
    if (!val) {
      return fallback
    }

    // if (val.length > 10) {
    //   val = val.substring(0, 10)
    // }
    console.log(val)
    return format(parse(val), 'yyyy-MM-dd')
  } catch (error) {
    return fallback
  }
}
